head.script:
// 전역변수
scwin.startDt = "";
scwin.userInfo = "";

scwin.onpageload = async function () {
    // 로그인 정보
    scwin.userInfo = $c.data.getMemInfo();

    var codeOptions = [
        { grpCd: "ZZ210", compID: "lc_cartypeCd" } // 셀렉트
    ];

    await $c.data.setCommonCode(codeOptions);

    dma_combo1.set("cmd", "retriveHomeClsList");
    var e = await $c.sbm.execute(sbm_combo1);     // 사업부문 콤보박스 셋팅

    // 서비스 후처리
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        //for=ds_lux_wrkPlCd event=OnLoadCompleted(rowCnt)
        lc_wrkPlCd.setSelectedIndex(0);
        if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
            lc_wrkPlCd.setValue(scwin.userInfo.fixWrkPlCd);
        }
    }

    lc_homeClsCd.setSelectedIndex(0);
    lc_homeClsCd.setValue(scwin.userInfo.eqHomeClsCd); // 정비소속구분코드
    scwin.lc_homeClsCd_onviewchange();

    ed_wrkStDt.focus();
};

scwin.onUdcCompleted = function () {
    // 초기값 셋팅
    var today = $c.date.getServerDateTime("yyyyMM");
    scwin.startDt = today + "01";
    var endDt = today + $c.date.getLastDateOfMonth(today);

    ed_wrkStDt.setValue(scwin.startDt);
    ed_wrkEndDt.setValue(endDt);
};

// 조회
scwin.f_Retrieve = async function (e) {
    let ret = await $c.gus.cfValidate([tb_wrk], null, true);

    if (!ret) return;

    ret = await $c.gus.cfIsAfterDate(ed_wrkStDt.getValue(), ed_wrkEndDt.getValue());

    if (!ret) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ed_wrkStDt.focus();
        return;
    }

    // 조회데이터셋팅
    dma_fix_work_re.set("termFrom", ed_wrkStDt.getValue());
    dma_fix_work_re.set("termTo", ed_wrkEndDt.getValue());
    dma_fix_work_re.set("repFixWrkPlCd", lc_repWrkPlCd.getValue());
    dma_fix_work_re.set("fixWrkPlCd", lc_wrkPlCd.getValue());
    dma_fix_work_re.set("cartypeCd", lc_cartypeCd.getValue());
    dma_fix_work_re.set("acctDeptCd", ed_acctDeptCd.getValue());
    dma_fix_work_re.set("eqCd", ed_eqCd.getValue());

    $c.sbm.execute(sbm_retrieve);
};

scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    var pWhere = "";

    switch (disGubun) {
        case 1: // 장비 팝업
            await udc_eqCd.cfCommonPopUp(
                function (rtnList) {
                    if (rtnList != null) {
                        if (rtnList[0] == "N/A") return;
                        ed_eqCd.setValue(rtnList[0]);
                        ed_vehclNo.setValue(rtnList[1]);
                    } else {
                        ed_eqCd.setValue("");
                        ed_vehclNo.setValue("");
                    }
                },
                ed_eqCd.getValue().trim(), // 화면에서의 Code Element의	Value
                ed_vehclNo.getValue(), // 화면에서의 Name Element의	Value
                pClose, // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                null, // 검색 결과	컬럼의 보여주는	개수
                null, // Title순서	
                null, // 보여주는 각 컬럼들의 폭	
                null, // 컬럼중에서 숨기는	컬럼 지정	
                lc_homeClsCd.getValue(), // SQL절의 WHERE절에	원하는 조건을 선택함
                null, // POP-UP뛰을때 원도우의	사용자 정의	폭
                null, // POP-UP뛰을때 우도우의	사용자 정의	높이	
                null, // 윈도우 위치 Y좌표	
                null, // 윈도우 위치 X좌표
                null, // 중복체크여부	("F")
                "F", // 전체검색허용여부	("F")
                "장비,장비코드,차량번호"// POP-UP Window Title
            );
            break;
        case 2: // 귀속부서 팝업
            await udc_acctDeptCd.cfCommonPopUp(
                function (rtnList) {
                    if (rtnList != null) {
                        if (rtnList[0] == "N/A") return;
                        ed_acctDeptCd.setValue(rtnList[0]);
                        ed_acctDeptNm.setValue(rtnList[1]);
                    } else {
                        ed_acctDeptCd.setValue("");
                        ed_acctDeptNm.setValue("");
                    }
                },
                ed_acctDeptCd.getValue().trim(), // 화면에서의 Code Element의	Value
                ed_acctDeptNm.getValue(), // 화면에서의 Name Element의	Value
                pClose, // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                null, // 검색 결과	컬럼의 보여주는	개수
                null, // Title순서	
                null, // 보여주는 각 컬럼들의 폭	
                null, // 컬럼중에서 숨기는	컬럼 지정	
                pWhere, // SQL절의 WHERE절에	원하는 조건을 선택함
                null, // POP-UP뛰을때 원도우의	사용자 정의	폭
                null, // POP-UP뛰을때 우도우의	사용자 정의	높이	
                null, // 윈도우 위치 Y좌표	
                null, // 윈도우 위치 X좌표
                null, // 중복체크여부	("F")
                "T", // 전체검색허용여부	("F")
                "귀속부서,부서코드,부서명"// POP-UP Window Title
            );
            break;
    }
};

scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = inObj.getValue();

    // inObj가 코드 필드일 경우 팝업
    if ($c.gus.cfIsNull(isCode) || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');

        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

// 조회조건 지우기
scwin.f_FieldClear = async function () {
    $c.gus.cfInitObjects(tb_wrk, null);

    lc_homeClsCd.setValue(scwin.userInfo.eqHomeClsCd); // 정비소속구분코드
    await scwin.lc_homeClsCd_onviewchange();

    if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
        lc_repWrkPlCd.setValue(scwin.userInfo.fixWrkPlCd); // 정비작업장코드
        scwin.lc_repWrkPlCd_onviewchange(); 
    }
};

// 엑셀다운로드
scwin.f_Excel = function () { 
    var count = ds_fix_work_list.getRowCount();

    if (!(count > 0)) return;

    var colSpan = gr_work_pl.hiddenList.filter(val => val === false).length;

    var options = {
        fileName: "차량별계정별 조회.xlsx",
        sheetName: "차량별계정별 조회",
        startRowIndex: 7,
        startColumnIndex: 0,
        type: 1
    };

    var infoArr = [{
        rowIndex: 0,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: "차량별계정별 조회",
        textAlign: "center",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 2,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `정비기간 [${$c.date.formatDate(ed_wrkStDt.getValue(), "date")} ~ ${$c.date.formatDate(ed_wrkEndDt.getValue(), "date")}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 3,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `사업부문 [${lc_homeClsCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 4,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `대표정비작업장 [${lc_repWrkPlCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 5,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `정비작업장 [${lc_wrkPlCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 6,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `장비구분 [${lc_cartypeCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }];

    $c.data.downloadGridViewExcel(gr_work_pl, options, infoArr);
};

// 대표정비작업장콤보 조회
scwin.f_RetrieveSecond = function (param1) { 
    dma_combo.set("cmd", "retriveFixWrkList");
    dma_combo.set("strVal", param1);

    $c.sbm.execute(sbm_combo);          
};

// 사업부문 콤보박스 선택시 발생하는 이벤트
scwin.lc_homeClsCd_onviewchange = function () {
    //for=lux_homeClsCd event=OnSelChange()
    var luxIndex = lc_homeClsCd.getValue();

    // 대표정비작업장콤보 조회
    scwin.f_RetrieveSecond(luxIndex);
};

// 대표정비작업장 콤보박스 선택시 발생하는 이벤트
scwin.lc_repWrkPlCd_onviewchange = function () {
    //for=lux_repWrkPlCd event=OnSelChange()
    if (lc_repWrkPlCd.getValue() == "") return;

    dma_lc_wrkPlCd.set("sysCd", "PsCommonEBC");
    dma_lc_wrkPlCd.set("queryId", "retriveWrkplList");
    dma_lc_wrkPlCd.set("param2", lc_repWrkPlCd.getValue());

    $c.sbm.execute(sbm_lc_wrkPlCd);             // 정비작업장 콤보박스 셋팅
};

// 귀속부서 컴포넌트에서 포커스 잃었을 때 발생하는 이벤트
scwin.udc_acctDeptCd_onblurCodeEvent = function (e) {
    //for=em_acctDeptCd event=OnKillFocus()
    scwin.f_chkOpenCommonPopUp(ed_acctDeptCd, ed_acctDeptNm, 2, false);
};

// 귀속부서 컴포넌트 돋보기버튼 클릭이벤트
scwin.udc_acctDeptCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(), 'F', 'T');
};

// 장비 컴포넌트에서 포커스 잃었을 때 발생하는 이벤트
scwin.udc_eqCd_onblurCodeEvent = function (e) {
    //for=em_eqCd event=OnKillFocus()
    scwin.f_chkOpenCommonPopUp(ed_eqCd, ed_vehclNo, 1, false);
};

// 장비 컴포넌트 돋보기버튼 클릭이벤트
scwin.udc_eqCd_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_eqCd.getValue(), ed_vehclNo.getValue(), 'F', 'T');
};

/**
 * 서비스 후처리
 */
// 조회 후처리
scwin.sbm_retrieve_submitdone = async function () {
    ds_crosstab.removeAll(); // 기존 데이터 지움

    var rowCount = ds_fix_work_list.getRowCount();

    gr_work_pl.setColumnVisible("column68", true);

    for (var i = 1; i <= 10; i++) {
        gr_work_pl.setColumnVisible("bilgAmt" + i, false);
    }

    if (rowCount == 0) {
        total.setValue(0);      // 총건수
        await $c.gus.cfAlertMsg("조회된 데이터가 없습니다.");
        return;
    }

    var options = {};
    options.sortIndex = "vehclNo outAcctCd";
    options.sortOrder = "1 1";

    ds_fix_work_list.multisort(options);

    var oringJSON = ds_fix_work_list.getAllJSON();
    var colData = [];
    var crossRJson = {};
    var allJson = [];

    oringJSON.forEach(function (rowJson) {
        //컬럼 생성
        if (!colData.includes(rowJson.outAcctCd)) {
            colData.push(rowJson.outAcctCd);
        }

        if (colData.length >= 11) return; //colData가 11개 이상이면 컬럼수 추가 해줘야함.

        var keyData = rowJson.vehclNo + "_" + rowJson.acctDeptNm + "_" + rowJson.eqKndCd + "_" + rowJson.prdyr;

        if (!crossRJson[keyData]) {
            crossRJson[keyData] = rowJson
        }

        var outAcctCdidx = colData.indexOf(rowJson.outAcctCd);

        if (outAcctCdidx > -1) {
            crossRJson[keyData]["bilgAmt" + (outAcctCdidx + 1)] = rowJson.bilgAmt
        }
    });

    for (key in crossRJson) {
        allJson.push(crossRJson[key]);
    }

    ds_crosstab.setJSON(allJson);

    gr_work_pl.setColumnVisible("column68", false);

    for (var i = 1; i <= colData.length; i++) {
        gr_work_pl.setHeaderValue("column" + i, colData[i - 1]);
        gr_work_pl.setColumnVisible("bilgAmt" + i, true);
    }

    total.setValue(ds_crosstab.getRowCount());      // 총건수
};

// 정비작업장 콤보박스 조회 후처리
scwin.sbm_lc_wrkPlCd_submitdone = function () {
    //for=ds_lux_wrkPlCd event=OnLoadCompleted(rowCnt)
    lc_wrkPlCd.setSelectedIndex(0);

    if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
        lc_wrkPlCd.setValue(scwin.userInfo.fixWrkPlCd); // 정비작업장코드
    }
};

// 대표정비작업장 콤보박스 조회 후처리
scwin.sbm_combo_submitdone = function () { 
    //for=co_ds_combo event=OnLoadCompleted(rowCnt)
    ds_combo.sort("code", 0); //tobe추가 : asis와 동일하게 하기 위해 추가.

    lc_repWrkPlCd.setSelectedIndex(0);

    if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
        lc_repWrkPlCd.setValue(scwin.userInfo.fixWrkPlCd);
    }

    scwin.lc_repWrkPlCd_onviewchange();               // 이벤트 발생안해서 강제 호출
};

// 합계 컬럼 푸터 포멧
scwin.zeroToEmpty = function (data) {
    var value = "";

    if (data != 0) {
        value = $c.num.formatNumber(data);
    }

    return value;
};
